/*===================================================================================================================================*/
/*  U1      u1_g_VdfEsoRx_ETH_AUDIO(void)                                                                                            */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      -                                                                                                                */
/*  Return:         -                                                                                                                */
/*===================================================================================================================================*/
U1      u1_g_VdfEsoRx_ETH_AUDIO(void)
{
    static const U1 u1_s_VDF_ESO_MM_AUDIO_ACT = (U1)2U;
    U1              u1_t_rx;
    U1              u1_t_ava_rx;

    u1_t_rx = (U1)0U;
    vd_g_HmiVardefRecieveSig((U1)HMIVARDEF_SIG_EXIST_ADO, &u1_t_rx);
    if(u1_t_rx == u1_s_VDF_ESO_MM_AUDIO_ACT){
        u1_t_ava_rx = (U1)VDF_ESO_AVA_RX_ACT;
    }
    else{
        u1_t_ava_rx = (U1)VDF_ESO_AVA_RX_UNK;
    }

    return(u1_t_ava_rx);
}
